agent_output:
{
  "domain_analysis": {
    "business_context": "A global logistics platform is adding a driver-facing earnings transparency feature across three jurisdictions with fundamentally different labor law regimes. The feature must show base pay, per-delivery bonuses, tips, and deductions in real time. The jurisdictions differ on driver classification (employee vs. independent contractor), legal obligations around wage transparency, and procedural requirements (works council approval). This is not a single feature with locale strings — it is three distinct compliance regimes sharing a common UI concept.",
    "bounded_context": "Driver Compensation / Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Earnings Breakdown", "definition": "The itemized view of all compensation components (base pay, bonuses, tips) and all deductions for a given period, presented to the driver." },
      { "term": "Base Pay", "definition": "The guaranteed compensation component before bonuses, tips, or deductions. For employees (CA), this must meet or exceed minimum wage. For contractors (ID), this is the agreed-upon rate per task or time unit." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to completing individual deliveries, which may include surge pricing, distance multipliers, or performance incentives." },
      { "term": "Tip", "definition": "Voluntary gratuity from the customer passed through to the driver. In California, tips may not be counted toward minimum wage obligations." },
      { "term": "Deduction", "definition": "Any amount subtracted from gross earnings. For employees (CA): taxes, benefits, legally mandated withholdings. For contractors (ID): platform fees, equipment charges. Each jurisdiction defines what deductions are permissible and must be disclosed." },
      { "term": "Net Earnings", "definition": "The final amount payable to the driver after all deductions are applied to gross earnings." },
      { "term": "Driver Classification", "definition": "The legal status of the driver — employee or independent contractor — which determines applicable labor law, tax treatment, and disclosure obligations. This is jurisdiction-specific and non-negotiable." },
      { "term": "Works Council Approval (Betriebsrat)", "definition": "In Germany, the legally mandated co-determination process where the works council must formally approve changes to systems that affect compensation display or monitoring before they can be deployed to drivers." },
      { "term": "Earnings Period", "definition": "The time window for which earnings are aggregated and displayed — could be per-delivery, per-shift, daily, weekly, or pay-period. Definition may vary by jurisdiction." },
      { "term": "Real-Time Earnings", "definition": "Earnings data updated and visible to the driver as deliveries are completed within the current earnings period, not delayed to a later pay cycle." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "The displayed earnings breakdown must always satisfy the invariant: Base Pay + Per-Delivery Bonuses + Tips - Deductions = Net Earnings. No rounding discrepancy greater than the smallest currency unit is permitted.",
      "invariant": true,
      "invariant_justification": "If components do not sum to the displayed net, the system is producing corrupt financial data. This is an arithmetic integrity constraint — violation means the numbers are wrong.",
      "testable_assertion": "For any earnings breakdown displayed to a driver, summing all positive components and subtracting all deductions yields the displayed net earnings within ±1 smallest currency unit (cent, euro-cent, rupiah)."
    },
    {
      "id": "BR-2",
      "rule": "Every deduction shown in the breakdown must have a labeled category and a non-zero amount. No unnamed or zero-value deduction line items may appear.",
      "invariant": true,
      "invariant_justification": "An unexplained deduction is a data integrity failure — drivers cannot verify correctness if deductions are anonymous, and it creates immediate legal exposure in regulated jurisdictions.",
      "testable_assertion": "Every deduction in an earnings breakdown has a non-empty category label and an amount > 0 in the local currency."
    },
    {
      "id": "BR-3",
      "rule": "In California, the earnings breakdown MUST include all components required by California wage transparency law: gross pay, each deduction category (taxes, benefits, other withholdings), net pay, and hours worked. Tips must be shown as a separate line item and must not be included in base pay calculations for minimum wage compliance.",
      "invariant": true,
      "invariant_justification": "Failure to display legally mandated wage components for California employees violates state labor law (AB5, Labor Code §226). This is a legal compliance constraint that cannot be softened by policy.",
      "testable_assertion": "For any California driver, the earnings breakdown includes: base pay, hours worked, each deduction by category, tips as a separate line, and net pay."
    },
    {
      "id": "BR-4",
      "rule": "The Germany earnings transparency feature MUST NOT be deployed to German drivers until formal Betriebsrat (works council) approval has been obtained and recorded in the system.",
      "invariant": true,
      "invariant_justification": "Deploying compensation display changes without works council approval violates the German Works Constitution Act (BetrVG §87). This is a legal precondition, not a policy preference — violation exposes the company to injunctions and fines.",
      "testable_assertion": "The feature flag or rollout gate for Germany checks for a recorded Betriebsrat approval status; if absent or 'pending', the feature is not accessible to German drivers."
    },
    {
      "id": "BR-5",
      "rule": "Driver classification (employee vs. independent contractor) is determined by jurisdiction and must not be alterable by the feature itself. California drivers are employees. Indonesia drivers are independent contractors. Germany drivers' classification follows local determination.",
      "invariant": true,
      "invariant_justification": "Driver classification is a legal fact determined by jurisdiction, not a system preference. Misclassification creates catastrophic legal liability. The earnings feature must consume this classification — never set or override it.",
      "testable_assertion": "The earnings transparency feature reads driver classification from an authoritative source and never writes to or modifies it."
    },
    {
      "id": "BR-6",
      "rule": "Earnings must be displayed in the local currency of the driver's operating jurisdiction: USD for California, EUR for Germany, IDR for Indonesia.",
      "invariant": true,
      "invariant_justification": "Displaying earnings in a foreign currency would render the information meaningless for local compliance and driver comprehension. Currency is tied to the legal and tax jurisdiction.",
      "testable_assertion": "A driver operating in California sees earnings in USD; Germany in EUR; Indonesia in IDR."
    },
    {
      "id": "BR-7",
      "rule": "For California employee-drivers, the system must verify that the computed base pay for any earnings period meets or exceeds the applicable minimum wage multiplied by hours worked. If it does not, a compliance alert must be raised internally — this is not displayed to the driver but triggers an operational review.",
      "invariant": false,
      "invariant_justification": "The minimum wage threshold is a policy value set by law that changes over time. The rule that it must be checked is important, but the threshold itself is configurable and the alerting mechanism is a business process decision.",
      "testable_assertion": "When a California driver's base pay for an earnings period is less than (minimum wage × hours worked), an internal compliance alert is generated."
    },
    {
      "id": "BR-8",
      "rule": "For Indonesian independent contractors, platform fees or commissions deducted must be displayed transparently, even though local law does not require it. The platform's business decision is to show transparency globally — but the specific deduction categories shown in Indonesia may differ from employee jurisdictions.",
      "invariant": false,
      "invariant_justification": "Indonesia has no legal mandate for this transparency. Showing it is a business policy decision that could be revised. The categories and granularity are a product choice.",
      "testable_assertion": "Indonesian drivers see a breakdown that includes platform fees/commissions as named line items in their deductions."
    },
    {
      "id": "BR-9",
      "rule": "Real-time means earnings data is updated within the current earnings period as each delivery is completed. It does NOT mean sub-second live streaming. The breakdown must reflect the latest completed delivery within a reasonable refresh window.",
      "invariant": false,
      "invariant_justification": "The definition of 'real time' is a product/UX decision. The latency tolerance is a policy choice, not a physical or legal constraint.",
      "testable_assertion": "After a delivery is marked complete, the driver's earnings breakdown reflects that delivery's compensation within the defined refresh window."
    },
    {
      "id": "BR-10",
      "rule": "Earnings data displayed to a driver must be consistent with the payroll/payment system of record. The transparency feature is a read-only view — it must never modify, create, or delete compensation records.",
      "invariant": true,
      "invariant_justification": "If the display layer can mutate compensation data, the system has a critical integrity violation. This is a read-only projection of the source of truth.",
      "testable_assertion": "The earnings transparency feature performs only read operations against the compensation/payroll data store. No write, update, or delete operations are issued."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California has completed 3 deliveries in the current shift",
      "when": "The driver opens the earnings breakdown screen",
      "then": "They see base pay, hours worked, each per-delivery bonus, tips (separate line), itemized deductions (taxes, benefits, withholdings), and net earnings — all in USD, summing correctly"
    },
    {
      "id": "AC-2",
      "given": "The Betriebsrat has NOT approved the earnings transparency feature for Germany",
      "when": "A German driver attempts to access the earnings breakdown",
      "then": "The feature is not available; the driver sees an appropriate message indicating the feature is not yet active in their region"
    },
    {
      "id": "AC-3",
      "given": "The Betriebsrat HAS formally approved the earnings transparency feature for Germany",
      "when": "A German driver opens the earnings breakdown after completing deliveries",
      "then": "They see their earnings breakdown in EUR with all components and deductions appropriate to the German context"
    },
    {
      "id": "AC-4",
      "given": "An Indonesian contractor-driver has completed deliveries today",
      "when": "The driver opens the earnings breakdown",
      "then": "They see base pay, per-delivery bonuses, tips, platform fees/commissions as named deductions, and net earnings — all in IDR"
    },
    {
      "id": "AC-5",
      "given": "A driver has just completed a delivery",
      "when": "The earnings breakdown is refreshed",
      "then": "The latest delivery's compensation components are reflected in the breakdown within the defined refresh window"
    },
    {
      "id": "AC-6",
      "given": "A California driver's computed base pay for the current period falls below minimum wage × hours worked",
      "when": "The earnings period is calculated",
      "then": "An internal compliance alert is raised for operational review; the driver's displayed earnings remain accurate to actual amounts"
    },
    {
      "id": "AC-7",
      "given": "Any driver in any jurisdiction views their earnings breakdown",
      "when": "The breakdown is rendered",
      "then": "Base Pay + Bonuses + Tips - Deductions = displayed Net Earnings (within ±1 smallest currency unit), and no deduction appears without a category label"
    },
    {
      "id": "AC-8",
      "given": "A California driver receives tips",
      "when": "The earnings breakdown is displayed",
      "then": "Tips appear as a separate line item and are NOT included in the base pay figure used for minimum wage calculations"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver has zero deliveries in the current period",
      "expected_behavior": "Earnings breakdown shows all components as zero or displays a clear 'no earnings yet' state. For California employees with clocked-in hours but no deliveries, base pay for hours worked must still appear."
    },
    {
      "scenario": "A tip is adjusted or reversed after initial display (customer modifies tip post-delivery)",
      "expected_behavior": "The earnings breakdown updates to reflect the adjusted tip amount. The adjustment must appear as a distinct line item or annotation — not a silent modification — so the driver understands why their total changed."
    },
    {
      "scenario": "A driver operates across jurisdiction boundaries (e.g., a delivery route that crosses from one jurisdiction to another)",
      "expected_behavior": "Earnings are attributed based on the driver's home jurisdiction or operating base, not the delivery route. The system must have a clear jurisdictional assignment rule — this needs explicit definition."
    },
    {
      "scenario": "Germany Betriebsrat approval is revoked or expires after initial rollout",
      "expected_behavior": "The feature must be immediately gated off for German drivers. The system must support disabling the feature post-launch, not just gating the initial rollout."
    },
    {
      "scenario": "Deductions exceed gross earnings, resulting in negative net pay",
      "expected_behavior": "The system must display the negative net amount accurately rather than clamping to zero. For California employees, this scenario should also trigger an internal compliance alert as it likely indicates an error."
    },
    {
      "scenario": "Currency conversion is involved (e.g., a tip received in a different currency)",
      "expected_behavior": "All amounts must be displayed in the driver's jurisdictional currency. Any conversion must happen upstream; the earnings breakdown never shows mixed currencies."
    },
    {
      "scenario": "The payroll system of record is temporarily unavailable",
      "expected_behavior": "The earnings breakdown must show stale data with a clear timestamp of last update, or an explicit 'data unavailable' state. It must NEVER show fabricated or estimated numbers."
    },
    {
      "scenario": "A new jurisdiction is added with different classification rules",
      "expected_behavior": "The system architecture must support jurisdiction-specific earnings breakdown configurations (required fields, deduction categories, gating conditions) without requiring changes to the core calculation logic."
    }
  ],

  "business_impact": {
    "financial": "Incorrect earnings display in California creates direct legal liability (Labor Code §226 penalties of $50-$100 per violation per pay period, plus actual damages). In Germany, deploying without Betriebsrat approval can result in injunctions halting operations. Globally, transparent earnings may reduce driver disputes and support ticket volume, saving operational costs.",
    "operational": "Three distinct compliance regimes require jurisdiction-aware feature flagging, not just i18n. Germany requires a gating workflow tied to an external legal process (works council). California requires ongoing minimum wage compliance monitoring. This increases operational complexity significantly beyond a simple UI feature.",
    "user": "Drivers gain trust and clarity about their compensation, which is a key driver retention lever in the gig economy. Poorly implemented transparency (wrong numbers, missing components) would destroy trust faster than no transparency at all. Indonesian contractors may see platform fees for the first time, which could cause friction if not communicated well.",
    "risk": "HIGH in California (legal non-compliance with wage statement laws), HIGH in Germany (works council violation), LOW-MEDIUM in Indonesia (no legal mandate, but reputational risk if transparency reveals unfavorable fee structures). Data accuracy risk across all jurisdictions — displaying wrong earnings is worse than not displaying them.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Legally entitled to this information; feature directly supports their rights as employees. Errors create actionable grievances." },
      { "group": "Drivers (Germany)", "impact": "Cannot receive feature until works council approves. May perceive delay as lack of commitment to transparency if not communicated." },
      { "group": "Drivers (Indonesia)", "impact": "Gain visibility into platform fees; may raise questions about fee fairness. Requires proactive communication strategy." },
      { "group": "Works Council (Germany)", "impact": "Must be engaged as a decision-making stakeholder, not merely notified. Has legal veto power over rollout." },
      { "group": "Legal/Compliance Team", "impact": "Must validate jurisdiction-specific requirements before launch. Ongoing obligation to update rules as laws change." },
      { "group": "Payroll/Finance Team", "impact": "Source-of-truth system must support real-time read access for the transparency feature without performance degradation." },
      { "group": "Product/UX Team", "impact": "Must design jurisdiction-aware UI that handles different required fields, currencies, and gating states." },
      { "group": "Customer Support", "impact": "Will receive driver inquiries about displayed earnings; needs training on jurisdiction-specific rules." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "This analysis involves legal and regulatory requirements across three jurisdictions (California labor law, German works constitution law, Indonesian contractor law) without formal legal review. Specific statutory requirements (exact fields mandated by CA Labor Code §226, precise Betriebsrat procedures under BetrVG §87, Indonesian contractor disclosure rules) need legal validation. Additionally, the spec is vague on 'real time' latency requirements and does not specify the German driver classification. Multiple ambiguities remain unresolved.",
    "high_confidence_areas": [
      "Arithmetic integrity of earnings breakdown (BR-1) is a universal invariant",
      "Betriebsrat approval is a hard legal gate for Germany — this is well-established German law",
      "California AB5 classification and tip separation requirements are well-documented",
      "Read-only projection pattern for the display layer (BR-10)",
      "Currency must match operating jurisdiction"
    ],
    "low_confidence_areas": [
      "Exact fields legally mandated by California Labor Code §226 for the digital display context (vs. paper wage statements)",
      "Whether German drivers are classified as employees or contractors under this platform's model",
      "Specific Betriebsrat approval workflow requirements and whether approval can be conditional or time-limited",
      "Indonesian regulatory landscape — assumed no mandate, but local counsel should confirm",
      "Definition of 'real time' refresh window — no SLA specified",
      "Cross-jurisdiction driver assignment rules"
    ],
    "assumptions": [
      "California drivers are employees per AB5 as stated in the spec",
      "German works council exists and is active for this platform's German operations",
      "Indonesia has no current legal mandate for contractor pay transparency",
      "The payroll/compensation system of record already exists and can support read queries",
      "Tips flow through the platform (not paid directly to drivers outside the system)",
      "Each driver operates primarily within a single jurisdiction"
    ]
  },

  "escalations": [
    {
      "type": "missing_context",
      "description": "The spec does not state whether German drivers are classified as employees or independent contractors. Germany has its own labor classification rules independent of AB5 and Indonesian law. This classification fundamentally changes what deduction categories, tax withholdings, and social insurance contributions must appear in the German earnings breakdown.",
      "affected_stakeholders": ["Drivers (Germany)", "Legal/Compliance Team", "Works Council (Germany)"],
      "options": [
        "A) Assume German drivers are employees (common in EU logistics) and include full employment deductions",
        "B) Assume German drivers are contractors and show contractor-appropriate breakdown",
        "C) Block German requirements definition until classification is confirmed"
      ],
      "recommendation": "C — Do not guess on German driver classification. Confirm with legal counsel before defining German-specific earnings fields. Incorrect classification assumptions would cascade into wrong deduction categories, wrong tax treatment display, and potentially invalid Betriebsrat submissions."
    },
    {
      "type": "ambiguity",
      "description": "'Real time' is undefined. Does it mean per-delivery instant update, sub-minute polling, per-shift aggregation, or something else? The latency SLA affects architecture (event-driven vs. polling), infrastructure cost, and driver expectations. A driver seeing stale data during a busy shift has a very different experience than one seeing instant updates.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Product/UX Team", "Payroll/Finance Team"],
      "options": [
        "A) Define real-time as 'within 60 seconds of delivery completion'",
        "B) Define real-time as 'updated on each screen refresh / pull-to-refresh'",
        "C) Define real-time as 'event-driven push update within seconds'"
      ],
      "recommendation": "B — Pull-to-refresh showing data current as of last delivery completion. This balances driver experience with system load and is the most common pattern in driver apps. But product must explicitly define the SLA."
    },
    {
      "type": "missing_context",
      "description": "The specific deduction categories required per jurisdiction are not enumerated in the spec. California requires itemized deductions by law, but the exact categories (federal tax, state tax, SDI, FICA, health insurance, etc.) need legal/payroll team input. Germany and Indonesia have entirely different deduction taxonomies.",
      "affected_stakeholders": ["Legal/Compliance Team", "Payroll/Finance Team", "Drivers (all jurisdictions)"],
      "options": [
        "A) Define a generic deduction model and let each jurisdiction configure categories",
        "B) Enumerate all categories per jurisdiction now with legal input",
        "C) Launch with high-level categories and iterate based on compliance review"
      ],
      "recommendation": "B — Enumerate jurisdiction-specific categories with legal and payroll input before implementation. A generic model risks missing legally required categories in California."
    }
  ],

  "rejection_reasons": []
}

